{"file_path":"/home/user/workspace/lib/posts.ts","content":"export type Post = {
  id: string
  title: string
  content: string
  createdAt: Date
}

const posts: Post[] = [
  {
    id: '1',
    title: 'Welcome',
    content: 'This is the first post.',
    createdAt: new Date(),
  },
]

export async function getPosts(): Promise<Post[]> {
  return [...posts].reverse()
}

export async function addPost(title: string, content: string): Promise<Post> {
  const post: Post = {
    id: crypto.randomUUID(),
    title,
    content,
    createdAt: new Date(),
  }
  posts.push(post)
  return post
}
"}

{"file_path":"/home/user/workspace/app/actions.ts","content":"'use server'

import { revalidateTag } from 'next/cache'
import { redirect } from 'next/navigation'
import { addPost } from '@/lib/posts'

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string
  const content = formData.get('content') as string

  const errors: { title?: string; content?: string } = {}

  if (!title || title.trim().length === 0) {
    errors.title = 'Title is required'
  }
  if (!content || content.trim().length === 0) {
    errors.content = 'Content is required'
  }

  if (Object.keys(errors).length > 0) {
    return { errors }
  }

  await addPost(title.trim(), content.trim())
  revalidateTag('posts')
  redirect('/')
}
"}

{"file_path":"/home/user/workspace/app/post-form.tsx","content":"'use client'

import { useActionState } from 'react'
import { useFormStatus } from 'react-dom'
import { createPost } from '@/app/actions'

function SubmitButton() {
  const { pending } = useFormStatus()

  return (
    <button type="submit" disabled={pending}>
      {pending ? 'Creating...' : 'Create Post'}
    </button>
  )
}

type FormState = {
  errors: {
    title?: string
    content?: string
  }
}

export function PostForm() {
  const [state, formAction] = useActionState<FormState, FormData>(
    createPost,
    { errors: {} }
  )

  return (
    <form action={formAction}>
      <div>
        <label htmlFor="title">Title</label>
        <input
          id="title"
          name="title"
          placeholder="Enter post title"
          required
        />
        {state?.errors?.title && (
          <p style={{ color: 'red', margin: '4px 0' }}>{state.errors.title}</p>
        )}
      </div>
      <div>
        <label htmlFor="content">Content</label>
        <textarea
          id="content"
          name="content"
          placeholder="Enter post content"
          rows={4}
          required
        />
        {state?.errors?.content && (
          <p style={{ color: 'red', margin: '4px 0' }}>{state.errors.content}</p>
        )}
      </div>
      <SubmitButton />
    </form>
  )
}
"}

{"file_path":"/home/user/workspace/app/page.tsx","content":"import { unstable_cache } from 'next/cache'
import { getPosts } from '@/lib/posts'
import { PostForm } from './post-form'

const getCachedPosts = unstable_cache(
  async () => getPosts(),
  ['posts-list'],
  { tags: ['posts'] }
)

export default async function Home() {
  const posts = await getCachedPosts()

  return (
    <main style={{ maxWidth: 640, margin: '0 auto', padding: '2rem 1rem' }}>
      <h1>Posts</h1>

      <section style={{ marginBottom: '2rem', border: '1px solid #ccc', padding: '1rem', borderRadius: 8 }}>
        <h2>Create a New Post</h2>
        <PostForm />
      </section>

      <section>
        <h2>All Posts</h2>
        {posts.length === 0 ? (
          <p>No posts yet. Create one above!</p>
        ) : (
          <ul style={{ listStyle: 'none', padding: 0 }}>
            {posts.map((post) => (
              <li
                key={post.id}
                style={{
                  border: '1px solid #ddd',
                  borderRadius: 8,
                  padding: '1rem',
                  marginBottom: '1rem',
                }}
              >
                <h3 style={{ margin: '0 0 0.5rem' }}>{post.title}</h3>
                <p style={{ margin: '0 0 0.5rem', whiteSpace: 'pre-wrap' }}>
                  {post.content}
                </p>
                <small style={{ color: '#666' }}>
                  {post.createdAt.toLocaleDateString(undefined, {
                    year: 'numeric',
                    month: 'long',
                    day: 'numeric',
                    hour: '2-digit',
                    minute: '2-digit',
                  })}
                </small>
              </li>
            ))}
          </ul>
        )}
      </section>
    </main>
  )
}
"}

